 	}
 }
+
+func TestORSet_DeleteThenMergeConvergence(t *testing.T) {
+	s1 := NewORSet()
+	s1.Add("x", "n1")
+
+	s2 := NewORSet()
+	s2.Merge(s1) // s2 observes n1's add
+	s2.Remove("x")
+
+	// s1 still holds x; without tombstones the merge resurrects it.
+	s2.Merge(s1)
+	if s2.Contains("x") {
+		t.Fatal("removal should survive merge from replica that still holds the element")
+	}
+}
+
+func TestORMap_DeleteThenMergeConvergence(t *testing.T) {
+	a := NewORMap()
+	a.Put("k", "v", 100, "n1")
+
+	b := NewORMap()
+	b.Merge(a) // b observes the key add
+	b.Delete("k")
+
+	b.Merge(a)
+	if _, ok := b.Get("k"); ok {
+		t.Fatal("delete should converge across merge with a replica that still holds the key")
+	}
+}

