 // (nodeID, counter) pair so that removes only affect observed adds.
 type ORSet struct {
 	mu       sync.RWMutex
 	entries  map[string]map[ORTag]struct{} // element -> set of tags
+	removed  map[string]map[ORTag]struct{} // element -> tombstoned tags
 	counters map[string]uint64             // nodeID -> next counter
 }

 // ORTag uniquely identifies an add operation.
 type ORTag struct {
 	NodeID  string
 	Counter uint64
 }

 // NewORSet creates an empty OR-Set.
 func NewORSet() *ORSet {
 	return &ORSet{
 		entries:  make(map[string]map[ORTag]struct{}),
+		removed:  make(map[string]map[ORTag]struct{}),
 		counters: make(map[string]uint64),
 	}
 }
@@ -89,11 +90,18 @@ func (s *ORSet) Add(elem string, nodeID string) {
 	s.entries[elem][tag] = struct{}{}
 }

 // Remove removes an element by clearing all its observed tags.
 // Concurrent adds (unseen tags) will survive.
 func (s *ORSet) Remove(elem string) {
 	s.mu.Lock()
 	defer s.mu.Unlock()
+	if tags := s.entries[elem]; len(tags) > 0 {
+		if s.removed[elem] == nil {
+			s.removed[elem] = make(map[ORTag]struct{})
+		}
+		for tag := range tags {
+			s.removed[elem][tag] = struct{}{}
+		}
+	}
 	delete(s.entries, elem)
 }
@@ -147,17 +155,38 @@ func (s *ORSet) Len() int {
 func (s *ORSet) Merge(other *ORSet) {
 	s.mu.Lock()
 	defer s.mu.Unlock()
 	other.mu.RLock()
 	defer other.mu.RUnlock()

+	for elem, tags := range other.removed {
+		if s.removed[elem] == nil {
+			s.removed[elem] = make(map[ORTag]struct{})
+		}
+		for tag := range tags {
+			s.removed[elem][tag] = struct{}{}
+		}
+	}
+
 	for elem, tags := range other.entries {
 		if s.entries[elem] == nil {
 			s.entries[elem] = make(map[ORTag]struct{})
 		}
 		for tag := range tags {
 			s.entries[elem][tag] = struct{}{}
 		}
 	}
+
+	for elem, rtags := range s.removed {
+		e := s.entries[elem]
+		if e == nil {
+			continue
+		}
+		for tag := range rtags {
+			delete(e, tag)
+		}
+		if len(e) == 0 {
+			delete(s.entries, elem)
+		}
+	}
+
 	for nodeID, c := range other.counters {
 		if c > s.counters[nodeID] {
 			s.counters[nodeID] = c
 		}
 	}
 }
